/* ============================================
   FAKTISK STUDIO — designsystem
   Henter farger og radii fra Figma-skissen
   ============================================ */

:root {
  --faktisk-blue: #0050FC;
  --faktisk-blue-hover: #0040D9;
  --bg-page: #9D9D9D;
  --bg-topbar: #707070;
  --bg-placeholder: #7B7B7B;
  --bg-letterbox: #878787;
  --bg-input: #D9D9D9;
  --text-on-blue: #FFFFFF;
  --text-topbar-title: #414141;
  --text-placeholder: #8B8B8B;
  --text-input: #313131;

  --radius-container: 30px;
  --radius-card: 15px;
  --radius-button: 11px;
  --radius-button-sm: 7px;
  --radius-input: 6px;

  --font-bold: "Haas Grot Text 75 Bold", "Helvetica Neue", Helvetica, Arial, sans-serif;
  --font-regular: "Haas Grot Text 55 Roman", "Helvetica Neue", Helvetica, Arial, sans-serif;
}

* { box-sizing: border-box; }

html, body {
  margin: 0;
  padding: 0;
  height: 100%;
  background: var(--bg-page);
  font-family: var(--font-regular);
  color: #fff;
  user-select: none;
  -webkit-user-select: none;
  overflow: hidden;
}

button {
  font-family: inherit;
  border: 0;
  cursor: pointer;
  background: none;
  color: inherit;
  padding: 0;
}

/* ============================================
   Hovedcontainer
   ============================================ */
.studio {
  background: var(--bg-page);
  border-radius: var(--radius-container);
  padding: 41px 26px;
  display: flex;
  flex-direction: column;
  gap: 10px;
  height: 100%;
  overflow: hidden;
}

/* ============================================
   Topp-bar
   ============================================ */
.topbar {
  background: var(--bg-topbar);
  border-radius: var(--radius-card);
  padding: 22px 27px;
