  display: flex;
  flex-direction: column;
  /* IKKE overflow:hidden — tekstbokser skal kunne stikke ut av kart-området */
  overflow: visible;
  min-width: 0;
  gap: 20px;
  padding: 8px 0;
}

/* «Før» / «Etter»-bokser over bildet */
.slider-labels {
  display: flex;
  justify-content: space-between;
  align-items: center;
  pointer-events: none;
  flex: 0 0 auto;
}
.slider-label {
  background: #0050FC;
  color: #fff;
  font-family: var(--font-bold);
  font-weight: bold;
  font-size: clamp(14px, 1.8cqw, 22px);
  padding: 0.3em 0.65em;
  border-radius: 5px;
  line-height: 1.25;
}

/* Sidebar: toggle + felt for Før/Etter-tekster */
.labels-section {
  display: flex;
  flex-direction: column;
  gap: 4px;
}
.check-row {
  display: flex;
  align-items: center;
  gap: 6px;
  font-size: 12px;
  color: #fff;
  font-family: var(--font-bold);
  font-weight: bold;
  cursor: pointer;
  user-select: none;
}
.check-row input[type="checkbox"] {
  accent-color: var(--faktisk-blue);
  margin: 0;
  cursor: pointer;
}
.labels-inputs {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 4px;
}
.labels-section.is-off .labels-inputs { display: none; }

/* Liten kompakt input — brukt på Før/Etter-tekst-felter (mindre enn URL-felt) */
.input-mini {
  background: var(--bg-input);
  border: 0;
  outline: 0;
  height: 32px;
  padding: 0 11px;
  border-radius: 6px;
  font-family: var(--font-bold);
  font-size: 12px;
  color: var(--text-input);
  font-weight: bold;
  width: 100%;
  box-sizing: border-box;
}
.input-mini::placeholder { color: #888; font-weight: normal; }

.slider-stage {
  position: relative;
  flex: 1;
  background: transparent;
  /* INGEN overflow:hidden her — slipper tekstbokser stikker ut.
     Klippingen skjer på .slider-clipper innenfor. */
  display: flex;
  align-items: center;
  justify-content: center;
  min-height: 0;
}

.slider-empty {
  padding: 40px;
  text-align: center;
}
.slider-empty p {
  max-width: 420px;
  font-size: 16px;
  color: #fff;
  margin: 0;
  line-height: 1.4;
}

.slider-preview {
  position: relative;
  width: 100%;
  height: 100%;
  user-select: none;
  container-type: inline-size;
}
/* Klipper for bildene + slider-handle + arrows/dots — tekstbokser ligger UTENFOR */
.slider-clipper {
  position: absolute;
  inset: 0;
  overflow: hidden;
  border-radius: 10px;
  background: var(--bg-letterbox);
}

.slider-img {
  position: absolute;
  width: 100%;
  height: 100%;
  object-fit: contain;
  display: block;
  pointer-events: none;
}

.slider-clip {
  position: absolute;
  width: 100%;
  height: 100%;
  clip-path: inset(0 50% 0 0);
  transition: clip-path 0.05s linear;
  pointer-events: none;
}

.slider-handle {
  position: absolute;
  top: 0;
  bottom: 0;
  left: 50%;
  width: clamp(5px, 0.9cqw, 9px);
  background: #fff;
  transform: translateX(-50%);
  cursor: ew-resize;
  z-index: 3;
}

.slider-handle__line {
  position: absolute;
  inset: 0;
  background: #fff;
}

.slider-handle__knob {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  width: clamp(28px, 4.2cqw, 38px);
  height: clamp(20px, 3cqw, 28px);
  background: #fff;
  border-radius: 4px;
  display: flex;
  align-items: center;
  justify-content: center;
  box-shadow: 0 2px 6px rgba(0,0,0,0.3);
}
.slider-handle__knob svg {
  width: 78%;
  height: 78%;
}

/* Tekstboks-seksjon i sidebar — Figma-stil med scroll-container */
.tb-section {
  display: flex;
  flex-direction: column;
  gap: 8px;
  flex: 1;          /* fyller all ledig plass i sidebar */
  min-height: 120px;
}
.tb-section__header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
}
/* Grå scroll-container som inneholder tekstboks-radene */
.tb-list {
  background: #929292;
  border-radius: 6px;
  padding: 10px 8px;
  flex: 1;
  min-height: 0;
  overflow-y: auto;
  display: flex;
  flex-direction: column;
  gap: 4px;
  scrollbar-width: thin;
  scrollbar-color: #6e6e6e #888;
}
.tb-list::-webkit-scrollbar { width: 8px; }
.tb-list::-webkit-scrollbar-track { background: #888; border-radius: 4px; }
.tb-list::-webkit-scrollbar-thumb { background: #6e6e6e; border-radius: 4px; }
.tb-list:empty::before {
  content: "Ingen tekstbokser ennå. Trykk «+ Legg til»";
  color: rgba(255,255,255,0.85);
  font-size: 12px;
  font-style: italic;
  padding: 4px 2px;
}

.tb-row {
  display: grid;
  grid-template-columns: 24px 1fr 24px 24px;
  gap: 4px;
  align-items: flex-start;
}
.tb-row__chip {
  height: 24px;
  border-radius: 6px;
  cursor: pointer;
  border: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 12px;
  font-weight: bold;
  font-family: var(--font-bold);
  color: #fff;
}
.tb-row__chip--light { background: #a2a2a2; }
.tb-row__chip--dark { background: var(--faktisk-blue); }

.tb-row__input {
  background: #D4D4D4;
  border: 0;
  outline: 0;
  border-radius: 6px;
  padding: 4px 9px;
  min-height: 24px;
  font-family: var(--font-bold);
  font-size: 12px;
  color: #212121;
  font-weight: bold;
  resize: vertical;
  line-height: 1.3;
  font-family: inherit;
}
.tb-row__input::placeholder { color: #666; font-weight: normal; }
input.tb-row__input { height: 24px; padding: 0 9px; }
textarea.tb-row__input { min-height: 36px; }

/* Peker-toggle (↗) og slett (×) — like små grå knapper */
.tb-row__btn {
  background: #a2a2a2;
  color: #fff;
  border: 0;
  width: 24px;
  height: 24px;
  border-radius: 6px;
  cursor: pointer;
  font-size: 12px;
  font-weight: bold;
  font-family: var(--font-bold);
  padding: 0;
  display: flex;
  align-items: center;
  justify-content: center;
}
.tb-row__btn:hover { background: #888; }
.tb-row__btn--active { background: #f18181; }   /* peker aktiv */
.tb-row__btn--del:hover { background: #c95c5c; }

/* Kompakt Figma-knapp — brukes overalt i sidebar */
.btn-mini {
  background: var(--faktisk-blue);
  color: #fff;
  font-family: var(--font-bold);
  font-weight: bold;
  font-size: 12px;
  padding: 5px 9px;
  border-radius: 6px;
  border: 0;
  cursor: pointer;
  white-space: nowrap;
  line-height: 1.3;
}
.btn-mini:hover:not(:disabled) { background: var(--faktisk-blue-hover); }
.btn-mini:disabled { opacity: 0.4; cursor: not-allowed; }
.btn-mini--block { width: 100%; text-align: center; }
.btn-mini--light { background: #a2a2a2; }
.btn-mini--light:hover:not(:disabled) { background: #888; }

.tb-add-buttons {
  display: flex;
  gap: 4px;
  flex-wrap: wrap;
  justify-content: flex-end;
}

/* Tekstbokser PÅ preview (drag-bare) — matcher embed-størrelser */
.tb-overlay {
  position: absolute;
  padding: 0.3em 0.65em;
  border-radius: 5px;
  font-family: var(--font-bold);
  font-weight: bold;
  font-size: clamp(14px, 1.8cqw, 26px);
  line-height: 1.25;
  cursor: move;
  user-select: none;
  pointer-events: auto;
  white-space: nowrap;
  transform: translate(-50%, -50%);
  z-index: 4;
  box-shadow: 0 2px 6px rgba(0,0,0,0.3);
}
.tb-overlay--light {
  background: #D9D9D9;
  color: #212121;
  font-weight: normal;
  font-size: clamp(14px, 1.6cqw, 22px);
  white-space: pre-wrap;
  max-width: 38%;
}
.tb-overlay--dark { background: #0050fc; color: #fff; }
.tb-overlay.is-selected { outline: 2px dashed #fff; outline-offset: 2px; }

/* Markeringer (frittstående sirkler) i preview */
.bm-marker {
  position: absolute;
  transform: translate(-50%, -50%);
  aspect-ratio: 1;
  cursor: move;
  z-index: 4;
  box-shadow: 0 2px 6px rgba(0,0,0,0.4);
}
.bm-marker--filled {
  background: #0050fc;
  border-radius: 50%;
}
.bm-marker--open {
  border: 4px solid #0050fc;
  border-radius: 50%;
  background: transparent;
}
.bm-marker__scale {
  position: absolute;
  right: -8px;
  bottom: -8px;
  width: 16px;
  height: 16px;
  background: #fff;
  border: 2px solid #0050fc;
  border-radius: 50%;
  cursor: nwse-resize;
  z-index: 5;
}

/* Marker-seksjon i sidebar — samme stil som tb-section */
.marker-section { display: flex; flex-direction: column; gap: 8px; flex: 0 0 auto; }

/* Peker-sirkel — bevarer proporsjon (HTML-div, ikke SVG) + puls-ring.
   Farge styres via variant-modifier (--dot-color custom prop). */
.tb-pointer-circle {
  position: absolute;
  width: 28px;
  height: 28px;
  transform: translate(-50%, -50%);
  cursor: move;
  z-index: 5;
  pointer-events: auto;
  --dot-color: #fff;
}
.tb-pointer-circle--dark { --dot-color: #0050fc; }
.tb-pointer-circle--light { --dot-color: #fff; }
.tb-pointer-dot-inner {
  position: absolute;
  inset: 0;
  background: var(--dot-color);
  border-radius: 50%;
  box-shadow: 0 1px 4px rgba(0,0,0,0.5);
  z-index: 2;
}
.tb-pointer-pulse {
  position: absolute;
  inset: 0;
  border-radius: 50%;
  background: var(--dot-color);
  opacity: 0.55;
  animation: tb-pulse 1.8s ease-out infinite;
  pointer-events: none;
  z-index: 1;
}
@keyframes tb-pulse {
  0%   { transform: scale(1);   opacity: 0.55; }
  80%  { transform: scale(2.6); opacity: 0;    }
  100% { transform: scale(2.6); opacity: 0;    }
}
